 58	// Initialize a generic auth service
 59	func (cfg Config) Initialize() (auth.AuthService, error) {
 60		httpClient := newSecureHTTPClient()
 61	
 62		// Discover OIDC endpoints
 63		jwksURL, introspectionURL, issuer, err := discoverOIDCConfig(httpClient, cfg.AuthorizationServer)
 64		if err != nil {
 65			return nil, fmt.Errorf("failed to discover OIDC config: %w", err)
 66		}
 67	
 68		// Override introspection URL if configured
 69		if cfg.IntrospectionEndpoint != "" {
 70			introspectionURL = cfg.IntrospectionEndpoint
 71		}
 72	
 73		// Create the keyfunc to fetch and cache the JWKS in the background
 74		kf, err := keyfunc.NewDefault([]string{jwksURL})
 75		if err != nil {
 76			return nil, fmt.Errorf("failed to create keyfunc from JWKS URL %s: %w", jwksURL, err)
 77		}
 78	
 79		a := &AuthService{
 80			Config:           cfg,
 81			kf:               kf,
 82			client:           httpClient,
 83			introspectionURL: introspectionURL,
 84			issuer:           issuer,
 85		}
 86		return a, nil
 87	}
 88	
 89	func newSecureHTTPClient() *http.Client {
 90		return &http.Client{
 91			Timeout: 10 * time.Second,
 92			Transport: &http.Transport{
 93				ForceAttemptHTTP2:     true,
 94				MaxIdleConns:          10,
 95				IdleConnTimeout:       90 * time.Second,
 96				TLSHandshakeTimeout:   5 * time.Second,
 97				ExpectContinueTimeout: 1 * time.Second,
 98			},
 99			CheckRedirect: func(req *http.Request, via []*http.Request) error {
100				return http.ErrUseLastResponse
101			},
102		}
103	}
