105	func discoverOIDCConfig(client *http.Client, AuthorizationServer string) (jwksURI string, introspectionEndpoint string, issuer string, err error) {
106		u, err := url.Parse(AuthorizationServer)
107		if err != nil {
108			return "", "", "", fmt.Errorf("invalid auth URL")
109		}
110		if u.Scheme != "https" {
111			log.Printf("WARNING: HTTP instead of HTTPS is being used for AuthorizationServer: %s", AuthorizationServer)
112		}
113	
114		oidcConfigURL, err := url.JoinPath(AuthorizationServer, ".well-known/openid-configuration")
115		if err != nil {
116			return "", "", "", err
117		}
118	
119		resp, err := client.Get(oidcConfigURL)
120		if err != nil {
121			return "", "", "", fmt.Errorf("failed to fetch OIDC config: %w", err)
122		}
123		defer resp.Body.Close()
124	
125		if resp.StatusCode != http.StatusOK {
126			return "", "", "", fmt.Errorf("unexpected status: %d", resp.StatusCode)
127		}
128	
129		// Limit read size to 1MB to prevent memory exhaustion
130		body, err := io.ReadAll(io.LimitReader(resp.Body, 1<<20))
131		if err != nil {
132			return "", "", "", err
133		}
134	
135		var config struct {
136			Issuer                string `json:"issuer"`
137			JwksUri               string `json:"jwks_uri"`
138			IntrospectionEndpoint string `json:"introspection_endpoint"`
139		}
140		if err := json.Unmarshal(body, &config); err != nil {
141			return "", "", "", err
142		}
143	
144		if config.JwksUri == "" {
145			return "", "", "", fmt.Errorf("jwks_uri not found in config")
146		}
147	
148		// Sanitize the resulting JWKS URI before returning it
149		parsedJWKS, err := url.Parse(config.JwksUri)
150		if err != nil {
151			return "", "", "", fmt.Errorf("invalid jwks_uri detected")
152		}
153		if parsedJWKS.Scheme != "https" {
154			log.Printf("WARNING: HTTP instead of HTTPS is being used for JWKS URI: %s", config.JwksUri)
155		}
156	
157		return config.JwksUri, config.IntrospectionEndpoint, config.Issuer, nil
158	}
