185	// Verifies generic JWT access token inside the Authorization header
186	func (a AuthService) GetClaimsFromHeader(ctx context.Context, h http.Header) (map[string]any, error) {
187		if a.McpEnabled {
188			return nil, nil
189		}
190	
191		tokenString := h.Get(a.Name + "_token")
192		if tokenString == "" {
193			return nil, nil
194		}
195	
196		// Parse and verify the token signature
197		token, err := jwt.Parse(tokenString, a.kf.Keyfunc)
198		if err != nil {
199			return nil, fmt.Errorf("failed to parse and verify JWT token: %w", err)
200		}
201	
202		if !token.Valid {
203			return nil, fmt.Errorf("invalid JWT token")
204		}
205	
206		claims, ok := token.Claims.(jwt.MapClaims)
207		if !ok {
208			return nil, fmt.Errorf("invalid JWT claims format")
209		}
210	
211		// Validate 'aud' (audience) claim
212		aud, err := claims.GetAudience()
213		if err != nil {
214			return nil, fmt.Errorf("could not parse audience from token: %w", err)
215		}
216	
217		isAudValid := false
218		for _, audItem := range aud {
219			if audItem == a.Audience {
220				isAudValid = true
221				break
222			}
223		}
224	
225		if !isAudValid {
226			return nil, fmt.Errorf("audience validation failed: expected %s, got %v", a.Audience, aud)
227		}
228	
229		return claims, nil
230	}
