241	// ValidateMCPAuth handles MCP auth token validation
242	func (a AuthService) ValidateMCPAuth(ctx context.Context, h http.Header) (map[string]any, error) {
243		tokenString := h.Get("Authorization")
244		if tokenString == "" {
245			return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: "missing access token", ScopesRequired: a.ScopesRequired}
246		}
247	
248		headerParts := strings.Split(tokenString, " ")
249		if len(headerParts) != 2 || strings.ToLower(headerParts[0]) != "bearer" {
250			return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: "authorization header must be in the format 'Bearer <token>'", ScopesRequired: a.ScopesRequired}
251		}
252	
253		tokenStr := headerParts[1]
254	
255		if isJWTFormat(tokenStr) {
256			return a.validateJwtToken(ctx, tokenStr)
257		}
258		return a.validateOpaqueToken(ctx, tokenStr)
259	}
260	
261	func isJWTFormat(token string) bool {
262		parts := strings.Split(token, ".")
263		if len(parts) != 3 {
264			return false
265		}
266		headerBytes, err := base64.RawURLEncoding.DecodeString(parts[0])
267		if err != nil {
268			return false
269		}
270		var header map[string]any
271		if err := json.Unmarshal(headerBytes, &header); err != nil {
272			return false
273		}
274		_, hasAlg := header["alg"]
275		return hasAlg
276	}
