278	// validateJwtToken validates a JWT token locally
279	func (a AuthService) validateJwtToken(ctx context.Context, tokenStr string) (map[string]any, error) {
280		token, err := jwt.Parse(tokenStr, a.kf.Keyfunc)
281		if err != nil || !token.Valid {
282			return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: "invalid or expired token", ScopesRequired: a.ScopesRequired}
283		}
284	
285		claims, ok := token.Claims.(jwt.MapClaims)
286		if !ok {
287			return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: "invalid JWT claims format", ScopesRequired: a.ScopesRequired}
288		}
289	
290		// Validate issuer
291		iss, err := claims.GetIssuer()
292		if err != nil {
293			return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: "could not parse issuer from token", ScopesRequired: a.ScopesRequired}
294		}
295		if iss == "" {
296			return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: "missing issuer claim in token", ScopesRequired: a.ScopesRequired}
297		}
298	
299		// Validate audience
300		aud, err := claims.GetAudience()
301		if err != nil {
302			return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: "could not parse audience from token", ScopesRequired: a.ScopesRequired}
303		}
304	
305		scopeClaim, _ := claims["scope"].(string)
306	
307		err = a.validateClaims(ctx, iss, aud, scopeClaim)
308		if err != nil {
309			return nil, err
310		}
311		return claims, nil
312	}
