424		mcpAuthEnabled := false
425		for _, authSvc := range s.ResourceMgr.GetAuthServiceMap() {
426			if genCfg, ok := authSvc.ToConfig().(generic.Config); ok && genCfg.McpEnabled {
427				mcpAuthEnabled = true
428				break
429			}
430		}
431	
432		// Manual PRM override
433		var cachedPrmBytes []byte
434		var prmConfig ProtectedResourceMetadata
435		if s.mcpPrmFile != "" {
436			var err error
437			cachedPrmBytes, err = os.ReadFile(s.mcpPrmFile)
438			if err != nil {
439				return nil, fmt.Errorf("failed to read manual PRM file at startup: %w", err)
440			}
441			// Unmarshal into the struct to strictly validate the schema
442			if err := json.Unmarshal(cachedPrmBytes, &prmConfig); err != nil {
443				return nil, fmt.Errorf("manual PRM file does not match expected schema: %w", err)
444			}
445		}
446	
447		// Register route if auth is enabled or a manual file is provided
448		if mcpAuthEnabled || s.mcpPrmFile != "" {
449			r.Get("/.well-known/oauth-protected-resource", func(w http.ResponseWriter, req *http.Request) {
450				// Serve from memory if file was loaded
451				if s.mcpPrmFile != "" {
452					w.Header().Set("Content-Type", "application/json")
453					w.WriteHeader(http.StatusOK)
454					if _, err := w.Write(cachedPrmBytes); err != nil {
455						s.logger.ErrorContext(req.Context(), "failed to write manual PRM file response", "error", err)
456					}
457					return
458				}
459	
460				prmHandler(s, w, req)
461			})
462		}
463	
464		// control plane
465		mcpR, err := mcpRouter(s)
466		if err != nil {
467			return nil, err
468		}
469	
470		r.Mount("/mcp", mcpR)
471		if cfg.EnableAPI {
472			apiR, err := apiRouter(s)
473			if err != nil {
474				return nil, err
475			}
476			r.Mount("/api", apiR)
477		} else {
478			r.Handle("/api/*", http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
479				err := errors.New("/api native endpoints are disabled by default. Please use the standard /mcp JSON-RPC endpoint")
480				_ = render.Render(w, r, newErrResponse(err, http.StatusGone))
481			}))
482		}
483		if cfg.UI {
484			webR, err := webRouter()
485			if err != nil {
486				return nil, err
487			}
488			r.Mount("/ui", webR)
489		}
490		// default endpoint for validating server is running
491		r.Get("/", func(w http.ResponseWriter, r *http.Request) {
492			_, _ = w.Write([]byte("🧰 Hello, World! 🧰"))
493		})
494	
495		return s, nil
496	}
