498	func mcpAuthMiddleware(s *Server) func(http.Handler) http.Handler {
499		return func(next http.Handler) http.Handler {
500			return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
501				// Find McpEnabled auth service
502				var mcpSvc *generic.AuthService
503				for _, authSvc := range s.ResourceMgr.GetAuthServiceMap() {
504					if genSvc, ok := authSvc.(*generic.AuthService); ok && genSvc.McpEnabled {
505						mcpSvc = genSvc
506						break
507					}
508				}
509	
510				// MCP Auth not enabled
511				if mcpSvc == nil {
512					next.ServeHTTP(w, r)
513					return
514				}
515	
516				claims, err := mcpSvc.ValidateMCPAuth(r.Context(), r.Header)
517				if err != nil {
518					var mcpErr *generic.MCPAuthError
519					if errors.As(err, &mcpErr) {
520						switch mcpErr.Code {
521						case http.StatusUnauthorized:
522							scopesArg := ""
523							if len(mcpErr.ScopesRequired) > 0 {
524								scopesArg = fmt.Sprintf(`, scope="%s"`, strings.Join(mcpErr.ScopesRequired, " "))
525							}
526							w.Header().Set("WWW-Authenticate", fmt.Sprintf(`Bearer resource_metadata="%s"%s`, s.toolboxUrl+"/.well-known/oauth-protected-resource", scopesArg))
527							render.Status(r, http.StatusUnauthorized)
528							render.JSON(w, r, jsonrpc.NewError(nil, jsonrpc.UNAUTHORIZED, mcpErr.Message, nil))
529							return
530						case http.StatusForbidden:
531							w.Header().Set("WWW-Authenticate", fmt.Sprintf(`Bearer error="insufficient_scope", scope="%s", resource_metadata="%s", error_description="%s"`, strings.Join(mcpErr.ScopesRequired, " "), s.toolboxUrl+"/.well-known/oauth-protected-resource", mcpErr.Message))
532							render.Status(r, http.StatusForbidden)
533							render.JSON(w, r, jsonrpc.NewError(nil, jsonrpc.FORBIDDEN, mcpErr.Message, nil))
534							return
535						}
536					}
537					// Fail closed on unexpected errors
538					s.logger.ErrorContext(r.Context(), "unexpected error during MCP auth validation", "error", err)
539					render.Status(r, http.StatusInternalServerError)
540					render.JSON(w, r, jsonrpc.NewError(nil, jsonrpc.INTERNAL_ERROR, "Internal Server Error", nil))
541					return
542				}
543	
544				ctx := util.WithAuthTokenClaims(r.Context(), claims)
545				r = r.WithContext(ctx)
546	
547				next.ServeHTTP(w, r)
548			})
549		}
550	}
