552	// Listen starts a listener for the given Server instance.
553	func (s *Server) Listen(ctx context.Context, certFile, keyFile string) error {
554		ctx, cancel := context.WithCancel(ctx)
555		defer cancel()
556	
557		if s.listener != nil {
558			return fmt.Errorf("server is already listening: %s", s.listener.Addr().String())
559		}
560		lc := net.ListenConfig{KeepAlive: 30 * time.Second}

560				span.SetStatus(codes.Error, err.Error())
561			}
562			span.End()
563		}()
564	
565		networkProtocolVersion := fmt.Sprintf("%d.%d", r.ProtoMajor, r.ProtoMinor)
566	
567		v, res, err := processMcpMessage(ctx, body, s, protocolVersion, toolsetName, promptsetName, r.Header, networkProtocolVersion)
568		if err != nil {
569			s.logger.DebugContext(ctx, fmt.Errorf("error processing message: %w", err).Error())
570		}
571	
572		// notifications will return empty string
573		if res == nil {
574			// Notifications do not expect a response
575			// Toolbox doesn't do anything with notifications yet
576			w.WriteHeader(http.StatusAccepted)
577			return
578		}
579	
580		// for v20250326, add the `Mcp-Session-Id` header
581		if v == v20250326.PROTOCOL_VERSION {
582			sessionId = uuid.New().String()
583			w.Header().Set("Mcp-Session-Id", sessionId)
584		}
585	
586		if session != nil {
587			// queue sse event
588			eventData, _ := json.Marshal(res)
589			select {
590			case session.eventQueue <- fmt.Sprintf("event: message\ndata: %s\n\n", eventData):
591				s.logger.DebugContext(ctx, "event queue successful")
592			case <-session.done:
593				s.logger.DebugContext(ctx, "session is close")
594			default:
595				s.logger.DebugContext(ctx, "unable to add to event queue")
596			}
597		}
598		if rpcResponse, ok := res.(jsonrpc.JSONRPCError); ok {
599			code := rpcResponse.Error.Code
600			switch code {
601			case jsonrpc.INTERNAL_ERROR:
602				// Map Internal RPC Error (-32603) to HTTP 500
603				w.WriteHeader(http.StatusInternalServerError)
604			case jsonrpc.INVALID_REQUEST:
605				var clientServerErr *util.ClientServerError
606				if errors.As(err, &clientServerErr) {
607					w.WriteHeader(clientServerErr.Code)
608				}
609				var mcpErr *generic.MCPAuthError
610				if errors.As(err, &mcpErr) {
611					switch mcpErr.Code {
612					case http.StatusForbidden:
613						w.Header().Set("WWW-Authenticate", fmt.Sprintf(`Bearer error="insufficient_scope", scope="%s", resource_metadata="%s", error_description="%s"`, strings.Join(mcpErr.ScopesRequired, " "), s.toolboxUrl+"/.well-known/oauth-protected-resource", mcpErr.Message))
614						w.WriteHeader(http.StatusForbidden)
615					case http.StatusUnauthorized:
616						scopesArg := ""
617						if len(mcpErr.ScopesRequired) > 0 {
618							scopesArg = fmt.Sprintf(`, scope="%s"`, strings.Join(mcpErr.ScopesRequired, " "))
619						}
620						w.Header().Set("WWW-Authenticate", fmt.Sprintf(`Bearer resource_metadata="%s"%s`, s.toolboxUrl+"/.well-known/oauth-protected-resource", scopesArg))
621						w.WriteHeader(http.StatusUnauthorized)
622					}
623				}
624			}
625		}
626	
627		// send HTTP response
628		render.JSON(w, r, res)
629	}
