631	// processMcpMessage process the messages received from clients
632	func processMcpMessage(ctx context.Context, body []byte, s *Server, protocolVersion string, toolsetName string, promptsetName string, header http.Header, networkProtocolVersion string) (string, any, error) {
633		operationStart := time.Now()
634	
635		logger, err := util.LoggerFromContext(ctx)
636		if err != nil {
637			return "", jsonrpc.NewError("", jsonrpc.INTERNAL_ERROR, err.Error(), nil), err
638		}
639	
640		// Generic baseMessage could either be a JSONRPCNotification or JSONRPCRequest
641		var baseMessage jsonrpc.BaseMessage
642		if err = util.DecodeJSON(bytes.NewBuffer(body), &baseMessage); err != nil {
643			// The id cannot be determined from an undecodable body (batch or parse
644			// error). Per JSON-RPC 2.0, the response id MUST be null in that case.
645			// See https://www.jsonrpc.org/specification#response_object
646	
647			// check if user is sending a batch request
648			var a []any
649			unmarshalErr := json.Unmarshal(body, &a)
650			if unmarshalErr == nil {
651				err = fmt.Errorf("not supporting batch requests")
652				return "", jsonrpc.NewError(nil, jsonrpc.INVALID_REQUEST, err.Error(), nil), err
653			}
654	
655			return "", jsonrpc.NewError(nil, jsonrpc.PARSE_ERROR, err.Error(), nil), err
656		}
657	
658		// Check if method is present
659		if baseMessage.Method == "" {
660			err = fmt.Errorf("method not found")
661			return "", jsonrpc.NewError(baseMessage.Id, jsonrpc.METHOD_NOT_FOUND, err.Error(), nil), err
662		}
663		logger.DebugContext(ctx, fmt.Sprintf("method is: %s", baseMessage.Method))
664	
665		// Check for JSON-RPC 2.0
666		if baseMessage.Jsonrpc != jsonrpc.JSONRPC_VERSION {
667			err = fmt.Errorf("invalid json-rpc version")
668			return "", jsonrpc.NewError(baseMessage.Id, jsonrpc.INVALID_REQUEST, err.Error(), nil), err
669		}
670	
671		// Create method-specific span with semantic conventions
672		// Note: Trace context is already extracted and set in ctx by the caller
673		ctx, span := s.instrumentation.Tracer.Start(ctx, baseMessage.Method,
674			trace.WithSpanKind(trace.SpanKindServer),
675		)
676		defer span.End()
677	
678		// Determine network transport and protocol based on header presence
679		networkTransport := "pipe" // default for stdio
680		networkProtocolName := "stdio"
681		if header != nil {
682			networkTransport = "tcp" // HTTP/SSE transport
683			networkProtocolName = "http"
684		}
685	
686		var metricErrorType string
687		genAIAttrs := &util.GenAIMetricAttrs{
688			NetworkProtocolName:    networkProtocolName,
689			NetworkProtocolVersion: networkProtocolVersion,
690		}
691		ctx = util.WithGenAIMetricAttrs(ctx, genAIAttrs)
692	
693		// Record operation duration metric on function exit
694		defer func() {
695			operationDuration := time.Since(operationStart).Seconds()
696			durationAttrs := []attribute.KeyValue{
697				attribute.String("mcp.method.name", baseMessage.Method),
698				attribute.String("network.transport", networkTransport),
699				attribute.String("network.protocol.name", networkProtocolName),
700				attribute.String("toolset.name", toolsetName),
701			}
702			if protocolVersion != "" {
703				durationAttrs = append(durationAttrs, attribute.String("mcp.protocol.version", protocolVersion))
704			}
705			if networkProtocolVersion != "" {
706				durationAttrs = append(durationAttrs, attribute.String("network.protocol.version", networkProtocolVersion))
707			}
708			// Add gen_ai attributes populated by method handlers
709			if genAIAttrs.OperationName != "" {
710				durationAttrs = append(durationAttrs, attribute.String("gen_ai.operation.name", genAIAttrs.OperationName))
711			}
712			if genAIAttrs.ToolName != "" {
713				durationAttrs = append(durationAttrs, attribute.String("gen_ai.tool.name", genAIAttrs.ToolName))
714			}
715			if genAIAttrs.PromptName != "" {
716				durationAttrs = append(durationAttrs, attribute.String("gen_ai.prompt.name", genAIAttrs.PromptName))
717			}
718			if metricErrorType != "" {
719				durationAttrs = append(durationAttrs, attribute.String("error.type", metricErrorType))
720			}
721			s.instrumentation.McpOperationDuration.Record(ctx, operationDuration, metric.WithAttributes(durationAttrs...))
722		}()
723	
724		// Set required semantic attributes for span according to OTEL MCP semcov
725		// ref: https://opentelemetry.io/docs/specs/semconv/gen-ai/mcp/#server
726		span.SetAttributes(
727			attribute.String("mcp.method.name", baseMessage.Method),
728			attribute.String("network.transport", networkTransport),
729			attribute.String("network.protocol.name", networkProtocolName),
730		)
731	
732		// Set client telemetry attributes from _meta["dev.mcp-toolbox/telemetry"]
733		if ta := util.TelemetryAttributesFromContext(ctx); ta != nil {
734			telemetryAttrs := make([]attribute.KeyValue, 0, 5)
735			if ta.ClientName != "" {
736				telemetryAttrs = append(telemetryAttrs, attribute.String("client.name", ta.ClientName))
737			}
738			if ta.ClientVersion != "" {
739				telemetryAttrs = append(telemetryAttrs, attribute.String("client.version", ta.ClientVersion))
740			}
741			if ta.ClientModel != "" {
742				telemetryAttrs = append(telemetryAttrs, attribute.String("client.model", ta.ClientModel))
743			}
744			if ta.ClientUserID != "" {
745				telemetryAttrs = append(telemetryAttrs, attribute.String("client.user.id", ta.ClientUserID))
746			}
747			if ta.ClientAgentID != "" {
748				telemetryAttrs = append(telemetryAttrs, attribute.String("client.agent.id", ta.ClientAgentID))
749			}
750			if len(telemetryAttrs) > 0 {
751				span.SetAttributes(telemetryAttrs...)
752			}
753		}
754	
755		// Set network protocol version if available
756		if networkProtocolVersion != "" {
757			span.SetAttributes(attribute.String("network.protocol.version", networkProtocolVersion))
758		}
759	
760		// Set MCP protocol version if available
761		if protocolVersion != "" {
762			span.SetAttributes(attribute.String("mcp.protocol.version", protocolVersion))
763		}
764	
765		// Set request ID
766		if baseMessage.Id != nil {
767			span.SetAttributes(attribute.String("jsonrpc.request.id", fmt.Sprintf("%v", baseMessage.Id)))
768		}
769	
770		// Set toolset name
771		span.SetAttributes(attribute.String("toolset.name", toolsetName))
772	
773		// Check if message is a notification
774		if baseMessage.Id == nil {
775			err := mcp.NotificationHandler(ctx, body)
776			if err != nil {
777				span.SetStatus(codes.Error, err.Error())
778			}
779			return "", nil, err
780		}
781	
782		// Add instrumentation to context for use in method handlers
783		ctx = util.WithInstrumentation(ctx, s.instrumentation)
784	
785		// Process the method
786		switch baseMessage.Method {
787		case "initialize":
788			var initReq struct {
789				Params struct {
790					ProtocolVersion string `json:"protocolVersion"`
791				} `json:"params,omitempty"`
792			}
793			if err := json.Unmarshal(body, &initReq); err != nil {
794				err = fmt.Errorf("fail to parse protocolVersion from initialize request")
795				return "", jsonrpc.NewError(baseMessage.Id, jsonrpc.INVALID_REQUEST, err.Error(), nil), err
796			}
797	
798			var version string
799			v := initReq.Params.ProtocolVersion
800			if slices.Contains(mcputil.SUPPORTED_PROTOCOL_VERSIONS, v) {
801				version = v
802			} else {
803				version = mcputil.LATEST_PROTOCOL_VERSION
804			}
805	
806			ctx = util.WithToolboxVersionKey(ctx, s.version)
807			result, err := mcp.ProcessMethod(ctx, version, baseMessage.Id, baseMessage.Method, tools.Toolset{}, prompts.Promptset{}, nil, body, nil)
808			if err != nil {
809				span.SetStatus(codes.Error, err.Error())
810				if rpcErr, ok := result.(jsonrpc.JSONRPCError); ok {
811					metricErrorType = rpcErr.Error.String()
812					span.SetAttributes(attribute.String("error.type", metricErrorType))
813				}
814				return "", result, err
815			}
816			span.SetAttributes(attribute.String("mcp.protocol.version", version))
817			return version, result, err
818		default:
819			toolset, ok := s.ResourceMgr.GetToolset(toolsetName)
820			if !ok {
821				err := fmt.Errorf("toolset does not exist")
822				rpcErr := jsonrpc.NewError(baseMessage.Id, jsonrpc.INVALID_REQUEST, err.Error(), nil)
823				metricErrorType = rpcErr.Error.String()
824				span.SetStatus(codes.Error, err.Error())
825				span.SetAttributes(attribute.String("error.type", metricErrorType))
826				return "", rpcErr, err
827			}
828			promptset, ok := s.ResourceMgr.GetPromptset(promptsetName)
829			if !ok {
830				err := fmt.Errorf("promptset does not exist")
831				rpcErr := jsonrpc.NewError(baseMessage.Id, jsonrpc.INVALID_REQUEST, err.Error(), nil)
832				metricErrorType = rpcErr.Error.String()
833				span.SetStatus(codes.Error, err.Error())
834				span.SetAttributes(attribute.String("error.type", metricErrorType))
835				return "", rpcErr, err
836			}
837			result, err := mcp.ProcessMethod(ctx, protocolVersion, baseMessage.Id, baseMessage.Method, toolset, promptset, s.ResourceMgr, body, header)
838			if err != nil {
839				span.SetStatus(codes.Error, err.Error())
840				// Set error.type based on JSON-RPC error code
841				if rpcErr, ok := result.(jsonrpc.JSONRPCError); ok {
842					metricErrorType = rpcErr.Error.String()
843					span.SetAttributes(attribute.Int("jsonrpc.error.code", rpcErr.Error.Code))
844					span.SetAttributes(attribute.String("error.type", metricErrorType))
845				}
846			}
847			return "", result, err
848		}
849	}
