851	type prmResponse struct {
852		Resource               string   `json:"resource"`
853		AuthorizationServers   []string `json:"authorization_servers"`
854		ScopesSupported        []string `json:"scopes_supported,omitempty"`
855		BearerMethodsSupported []string `json:"bearer_methods_supported"`
