858	// prmHandler generates the Protected Resource Metadata (PRM) file for MCP Authorization.
859	func prmHandler(s *Server, w http.ResponseWriter, r *http.Request) {
860		var server string
861		scopes := []string{}
862		for _, authSvc := range s.ResourceMgr.GetAuthServiceMap() {
863			cfg := authSvc.ToConfig()
864			if genCfg, ok := cfg.(generic.Config); ok {
865				if genCfg.McpEnabled {
866					server = genCfg.AuthorizationServer
867					if genCfg.ScopesRequired != nil {
868						scopes = genCfg.ScopesRequired
869					}
870					break
871				}
872			}
873		}
874	
875		res := prmResponse{
876			Resource:               s.toolboxUrl,
877			AuthorizationServers:   []string{server},
878			ScopesSupported:        scopes,
879			BearerMethodsSupported: []string{"header"},
880		}
881	
882		w.Header().Set("Content-Type", "application/json")
883		if err := json.NewEncoder(w).Encode(res); err != nil {
884			s.logger.ErrorContext(r.Context(), fmt.Sprintf("Failed to encode PRM response: %v", err))
885			http.Error(w, "Failed to encode PRM response", http.StatusInternalServerError)
886		}
887	}

