 31	// ToolConfigFactory defines the signature for a function that creates and
 32	// decodes a specific tool's configuration. It takes the context, the tool's
 33	// name, and a YAML decoder to parse the config.
 34	type ToolConfigFactory func(ctx context.Context, name string, decoder *yaml.Decoder) (ToolConfig, error)
 35	
 36	var toolRegistry = make(map[string]ToolConfigFactory)
 37	
 38	// Register allows individual tool packages to register their configuration
 39	// factory function. This is typically called from an init() function in the
 40	// tool's package. It associates a 'type' string with a function that can
 41	// produce the specific ToolConfig type. It returns true if the registration was
 42	// successful, and false if a tool with the same type was already registered.
 43	func Register(resourceType string, factory ToolConfigFactory) bool {
 44		if _, exists := toolRegistry[resourceType]; exists {
 45			// Tool with this type already exists, do not overwrite.
 46			return false
 47		}
 48		toolRegistry[resourceType] = factory
 49		return true
 50	}
 51	
 52	// DecodeConfig looks up the registered factory for the given type and uses it
 53	// to decode the tool configuration.
 54	func DecodeConfig(ctx context.Context, resourceType string, name string, decoder *yaml.Decoder) (ToolConfig, error) {
 55		factory, found := toolRegistry[resourceType]
 56		if !found {
 57			return nil, fmt.Errorf("unknown tool type: %q", resourceType)
 58		}
 59		toolConfig, err := factory(ctx, name, decoder)
 60		if err != nil {
 61			return nil, fmt.Errorf("unable to parse tool %q as type %q: %w", name, resourceType, err)
 62		}
 63		return toolConfig, nil
 64	}
