115	func (token AccessToken) ParseBearerToken() (string, error) {
116		headerParts := strings.Split(string(token), " ")
117		if len(headerParts) != 2 || strings.ToLower(headerParts[0]) != "bearer" {
118			return "", util.NewClientServerError("authorization header must be in the format 'Bearer <token>'", http.StatusUnauthorized, nil)
119		}
120		return headerParts[1], nil
121	}
