153	// Helper function that returns if a tool invocation request is authorized
154	func IsAuthorized(authRequiredSources []string, verifiedAuthServices []string) bool {
155		if len(authRequiredSources) == 0 {
156			// no authorization requirement
157			return true
158		}
159		for _, a := range authRequiredSources {
160			if slices.Contains(verifiedAuthServices, a) {
161				return true
162			}
163		}
164		return false
165	}
