266	func UnmarshalYAMLAuthServiceConfig(ctx context.Context, name string, r map[string]any) (auth.AuthServiceConfig, error) {
267		resourceType, ok := r["type"].(string)
268		if !ok {
269			return nil, fmt.Errorf("missing 'type' field or it is not a string")
270		}
271		dec, err := util.NewStrictDecoder(r)
272		if err != nil {
273			return nil, fmt.Errorf("error creating decoder: %s", err)
274		}
275	
276		switch resourceType {
277		case google.AuthServiceType:
278			actual := google.Config{Name: name}
279			if err := dec.DecodeContext(ctx, &actual); err != nil {
280				return nil, fmt.Errorf("unable to parse as %s: %w", name, err)
281			}
282			return actual, nil
283		case generic.AuthServiceType:
284			actual := generic.Config{Name: name}
285			if err := dec.DecodeContext(ctx, &actual); err != nil {
286				return nil, fmt.Errorf("unable to parse as %s: %w", name, err)
287			}
288			return actual, nil
289		default:
290			return nil, fmt.Errorf("%s is not a valid type of auth service", resourceType)
291		}
292	}
